// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decode an opaque cursor back into { created_at, id }.
 * Throws if the cursor is malformed or missing required fields.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.id === 'undefined' ||
        typeof decoded.created_at === 'undefined'
    ) {
        throw new Error('Malformed cursor');
    }

    // Validate the timestamp is parseable.
    if (Number.isNaN(Date.parse(decoded.created_at))) {
        throw new Error('Malformed cursor');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

async function getPosts(req, res) {
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const after = req.query.after;

    // Decode cursor if provided.
    let cursor = null;
    if (after) {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }
    }

    // Build the query. Fetch limit + 1 rows to detect a next page.
    let sql;
    let params;

    if (cursor) {
        // Keyset/seek predicate matching ORDER BY created_at DESC, id DESC.
        // Row tuple comparison: only return rows strictly "after" the cursor.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // N+1 trick: more rows than requested means there's a next page.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore ? encodeCursor(posts[posts.length - 1]) : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Key implementation notes

- **`(created_at, id) < ($1, $2)`** is PostgreSQL row-value (tuple) comparison. It compares lexicographically — first by `created_at`, then by `id` as a tie-breaker — which exactly mirrors `ORDER BY created_at DESC, id DESC`. Using `<` for a `DESC` sort gives you the rows that come *after* the cursor in scan order. This avoids the buggy manual expansion (`created_at < $1 OR (created_at = $1 AND id < $2)`), though that form is functionally equivalent if you can't use tuple syntax.
- **`base64url`** avoids `+`, `/`, and `=` characters that would otherwise need URL-encoding in the query string.
- **`created_at` is normalized to an ISO string** on encode so the round-trip is stable regardless of whether the driver returns a `Date` or a string.
- **Index requirement:** for this to be fast, you need a composite index matching the sort: `CREATE INDEX idx_posts_keyset ON posts (created_at DESC, id DESC) WHERE published = true;` (a partial index, since you always filter `published = true`).

## Why cursor-based pagination is superior here

1. **Constant performance at any depth.** `OFFSET 100000` forces Postgres to scan and discard 100k rows before returning your page — cost grows linearly with page number. A keyset predicate (`WHERE (created_at, id) < ...`) uses the index to *seek* directly to the start of the page, so page 5,000 is as fast as page 1.
2. **Stable results under writes.** With offsets, a row inserted or deleted while the user paginates shifts every subsequent page, causing skipped or duplicated items. A cursor anchors to a specific row's sort key, so concurrent inserts/deletes don't corrupt the sequence.
3. **No expensive COUNT.** `COUNT(*)` on a large table is a full scan (or index-only scan) every request. Dropping it removes that cost; `hasMore` from the N+1 trick gives the only signal a "load more" UI actually needs.

The trade-off: you lose random page access ("jump to page 47") and exact total counts — which is the right call for a `created_at DESC` feed that's consumed as an infinite scroll / "load more" list.

