// ─── Cursor Helpers ───────────────────────────────────────────────────────────

/**
 * Encodes a compound (created_at, id) cursor into an opaque base64 string.
 * @param {object} post - A post row with at least { id, created_at }
 * @returns {string} Base64-encoded cursor token
 */
function encodeCursor(post) {
    const payload = {
        created_at: post.created_at instanceof Date
            ? post.created_at.toISOString()
            : post.created_at,
        id: post.id,
    };
    return Buffer.from(JSON.stringify(payload)).toString('base64url');
}

/**
 * Decodes a base64 cursor token back to { created_at, id }.
 * Throws an Error (caught by the route handler) if the token is malformed.
 * @param {string} token - The raw cursor string from the query param
 * @returns {{ created_at: string, id: number }}
 */
function decodeCursor(token) {
    let parsed;

    try {
        const json = Buffer.from(token, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch {
        throw new Error('Cursor is not valid base64-encoded JSON.');
    }

    const { created_at, id } = parsed;

    if (!created_at || typeof id !== 'number') {
        throw new Error('Cursor is missing required fields: created_at, id.');
    }

    // Validate that created_at is a parseable date string
    if (Number.isNaN(Date.parse(created_at))) {
        throw new Error('Cursor contains an invalid created_at timestamp.');
    }

    return { created_at, id };
}


// ─── Route Handler ────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ──────────────────────────────────────────
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterToken = req.query.after ?? null;

    let cursor = null;

    if (afterToken !== null) {
        try {
            cursor = decodeCursor(afterToken);
        } catch (err) {
            return res.status(400).json({
                error: 'Invalid pagination cursor.',
                detail: err.message,
            });
        }
    }

    // ── 2. Build and run the query ──────────────────────────────────────────
    //
    // Sort order: created_at DESC, id DESC
    //
    // A compound cursor at position (T, N) splits the ordered set like this:
    //
    //   ┌─ already returned ─┐  ┌─ next page starts here ─┐
    //   created_at > T        │  created_at < T
    //   created_at = T, id > N│  created_at = T, id < N
    //                         N  (the cursor row itself)
    //
    // The WHERE clause below captures the "next page starts here" half.
    // Using (created_at, id) < ($1, $2) row-value syntax would be cleaner,
    // but explicit OR works with every PG version and indexes equally well
    // when there's a composite index on (created_at DESC, id DESC).

    let result;

    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                        created_at < $1
                     OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]   // fetch N+1
        );
    } else {
        // First page — no cursor filter needed
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]   // fetch N+1
        );
    }

    // ── 3. Apply the N+1 trick ──────────────────────────────────────────────
    //
    // If we got limit+1 rows back, there is at least one more page.
    // Trim the extra row before returning; derive the next cursor from
    // the last row we ARE returning (not the trimmed one).
    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;
    const nextCursor = hasMore ? encodeCursor(posts[posts.length - 1]) : null;

    // ── 4. Respond ──────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when on the last page
            limit,
        },
    });
}
```

---

## How it works end-to-end

| Step | What happens |
|---|---|
| **First request** | `GET /api/posts?limit=20` — no cursor, fetches first 21 rows, trims to 20, encodes row 20 as `nextCursor` |
| **Next page** | `GET /api/posts?limit=20&after=<token>` — decodes token to `(created_at, id)`, uses the OR-based WHERE to skip everything already seen |
| **Last page** | Query returns ≤ 20 rows → `hasMore: false`, `nextCursor: null` |

---

## Why cursor pagination is superior here

**1. No index scans past discarded rows (the core perf win)**  
`OFFSET N` forces PostgreSQL to read and throw away the first N rows every time, even though you never see them. A 10,000-row offset on a 10M-row table scans 10,000 index entries just to find the starting point. The cursor's `WHERE created_at < $1 OR (…)` jumps directly to the right position using the `(created_at DESC, id DESC)` index — O(log n) seek, not O(offset) scan.

**2. No duplicate/skipped rows under concurrent writes**  
With offset pagination, if a new post is inserted while a user pages through results, every subsequent page shifts by one row — the user either sees a duplicate or skips a post entirely. The cursor anchors to a specific row in the sort order, so inserts and deletes outside the already-seen range are invisible to the in-flight pagination session.

**3. No expensive `COUNT(*)`**  
`SELECT COUNT(*)` on a large table requires a sequential scan (or a full index scan). Removing it cuts query time in half on the first page and entirely on subsequent pages. The `hasMore` flag from the N+1 trick gives clients everything they need to drive a "Load more" button or infinite scroll without knowing the total.

**4. Stable under sort-key ties**  
The compound `(created_at, id)` cursor handles posts with identical timestamps correctly. Using only `created_at` would produce non-deterministic results when multiple posts share the same timestamp; adding `id` (a unique tiebreaker) makes the sort — and therefore the cursor position — fully deterministic.

